package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsQuoteCharacterSetWhenQuoteCharacterIsNull() throws Exception {
        // Create CSVFormat instance with quoteCharacter = null using reflection
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final field quoteCharacter to null
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);

        // Remove final modifier via reflection hack
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(quoteCharacterField, quoteCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        quoteCharacterField.set(format, null);

        assertFalse(format.isQuoteCharacterSet());
    }

    @Test
    void testIsQuoteCharacterSetWhenQuoteCharacterIsSet() throws Exception {
        // Create CSVFormat instance with quoteCharacter set to '"'
        CSVFormat format = CSVFormat.DEFAULT.withQuote('"');
        assertTrue(format.isQuoteCharacterSet());
    }
}
